// export default Taskcard


import React from 'react'

const Taskcard = ({ task }) => {
    return (
        <>
            <div className='task-card'>
                <div className='taskcard-header'>
                    <div className='task-title'>
                        {task.title}
                    </div>
                    <div className='task-icons'>
                        <div className='sub-icon'>
                            <button className='icon-button' type="button">
                                <img className='icon-img' src='/assets/add.png' alt="Add" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button className='icon-button' type="button">
                                <img className='icon-img' src='/assets/edit.png' alt="Edit" />
                            </button>
                        </div>
                        <div className='sub-icon'>
                            <button className='icon-button' type="button">
                                <img className='icon-img' src='/assets/delete.png' alt="Delete" />
                            </button>
                        </div>
                    </div>
                </div>
                <div className='sub-tasks'>
                    <ul>
                        <li><input type='checkbox' /></li>
                    </ul>
                </div>
            </div>
            <Stylesheet />
        </>
    )
}

const Stylesheet = () => {
    return <style>{`
        .task-card{
            margin-bottom:2rem;
        }
        .taskcard-header{
            display:flex;
            align-items:center;
            justify-content:space-between;
            padding-left:5px;
            padding-right:5px;
            flex-direction:row;
            background-color:var(--secondary-color);
            width:250px;
            min-height:50px;
            border-radius: 5px;
        }
        .task-icons{
            display:flex;
            align-items:center;
        }
        .icon-button{
            background:none;
            border:none;
            cursor:pointer;
        }
        .icon-img{
            height:20px;
            width:30px;
        }
        .task-title{
            width:100px;
            white-space: normal;
            overflow-wrap: break-word;
            word-break: break-word; /* or break-all for more aggressive */
        }
        .sub-tasks{
            display:flex;
            justify-content:left;
            align-items:center;
            background-color:yellow;
        }
    `}
    </style>
}

export default Taskcard
